import java.util.ArrayList;import java.util.Comparator;import java.util.List;import java.util.Map;
final class StrategyPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}
interface Strategy{String select(List<Map<String,Object>>candidates);}record MetricStrategy(String field)implements Strategy{public String select(List<Map<String,Object>>candidates){return candidates.stream().filter(v->Boolean.TRUE.equals(v.get("healthy"))).min(Comparator.<Map<String,Object>>comparingDouble(v->((Number)v.get(field)).doubleValue()).thenComparing(v->String.valueOf(v.get("name")))).orElseThrow(()->new PatternException("no_healthy_candidate")).get("name").toString();}}
@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){List<String>out=new ArrayList<>();for(Map<String,Object>value:(List<Map<String,Object>>)input.getOrDefault("selections",List.of())){Strategy strategy=switch(String.valueOf(value.get("strategy"))){case"cost"->new MetricStrategy("cost");case"latency"->new MetricStrategy("latency");default->throw new PatternException("unsupported_strategy");};out.add(strategy.select((List<Map<String,Object>>)value.getOrDefault("candidates",List.of())));}return Map.of("selected",out);}}
